 var _bI='<button class="rp-seg2-b'+(_if?' on':'')+'" data-view="items">'+_cs+'Items</button>';
 var _bP='<button class="rp-seg2-b'+(_if?'':' on')+'" data-view="packages">'+rpBoxSvg()+'Packages</button>';
